let tempArray = [];
let tempMarketplaceObj = {};
//let currentRow = configValuesTable.selectedDataIndex;

let currentDimension = components.configValuesTable.selectedRow.dimensions;

for(let i = 0; i < currentDimension.length; i++) {
  if(currentDimension[i].dimension_name.includes("LEGACY_")) {
    tempMarketplaceObj[currentDimension[i].dimension_name] = currentDimension[i][currentDimension[i].value];
  } else {
    let tempObj = {};
    tempObj.level = `L${i+1}`
    tempObj.key = currentDimension[i].dimension_name;
    tempObj.value = currentDimension[i][currentDimension[i].value];
    if(tempObj.value !== "") {
      tempArray.push(tempObj);
    }
  }
}
//dimensionKeyValueArray.setValue(tempArray);
await actions.setPageVariable("dimensionKeyValueArray",tempArray)
//marketplaceKeyValueObj.setValue(tempMarketplaceObj);
await actions.setPageVariable("marketplaceKeyValueObj",tempMarketplaceObj)
